import{_ as i,c as l,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"trivy","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/安全工具/trivy-安全工具.md","filePath":"github汇总/安全工具/trivy-安全工具.md"}'),t={name:"github汇总/安全工具/trivy-安全工具.md"};function o(n,a,h,s,c,d){return e(),l("div",null,a[0]||(a[0]=[r('<h1 id="trivy" tabindex="-1">trivy <a class="header-anchor" href="#trivy" aria-label="Permalink to “trivy”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>trivy</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>aquasecurity</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>安全工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>开发者和运维人员需要多种工具才能完成全面的安全扫描，效率低下。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>全面多功能的安全扫描器，可扫描容器镜像、文件系统、Git仓库、虚拟机镜像、Kubernetes。可发现操作系统包和软件依赖中的已知漏洞（CVE）、基础设施即代码的配置问题、敏感信息泄露、软件许可证问题。支持大多数流行的编程语言、操作系统和平台。集成GitHub Actions、Kubernetes operator、VS Code插件等众多平台。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>一个工具完成多种安全扫描</li><li>支持容器镜像、文件系统、Git仓库、Kubernetes等多种目标</li><li>可发现漏洞、配置问题、敏感信息、许可证问题</li><li>集成众多主流平台和工具</li><li>Aqua Security开源项目</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/aquasecurity/trivy" target="_blank" rel="noreferrer">https://github.com/aquasecurity/trivy</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用Trivy进行安全扫描的开发者和运维人员。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><strong>检查操作系统</strong><ul><li>执行命令：无</li><li>通过标准：macOS、Linux或Windows</li></ul></li></ol><h3 id="主路径-使用homebrew安装-macos-linux" tabindex="-1">主路径：使用Homebrew安装（macOS/Linux） <a class="header-anchor" href="#主路径-使用homebrew安装-macos-linux" aria-label="Permalink to “主路径：使用Homebrew安装（macOS/Linux）”">​</a></h3><p><strong>步骤1：安装Trivy</strong></p><ul><li>目标：通过Homebrew安装Trivy</li><li>位置：终端</li><li>命令：<code>brew install trivy</code></li><li>成功标志：安装成功提示</li><li>失败处理：检查Homebrew是否正确安装</li></ul><p><strong>步骤2：验证安装</strong></p><ul><li>目标：确认Trivy安装成功</li><li>位置：终端</li><li>命令：<code>trivy --version</code></li><li>成功标志：显示Trivy版本号</li><li>失败处理：重新安装</li></ul><h3 id="备选路径1-使用docker" tabindex="-1">备选路径1：使用Docker <a class="header-anchor" href="#备选路径1-使用docker" aria-label="Permalink to “备选路径1：使用Docker”">​</a></h3><p><strong>步骤1：拉取镜像</strong></p><ul><li>目标：获取Trivy Docker镜像</li><li>位置：终端</li><li>命令：<code>docker pull aquasec/trivy</code></li><li>成功标志：镜像拉取成功</li><li>失败处理：检查Docker是否运行</li></ul><p><strong>步骤2：运行扫描</strong></p><ul><li>目标：使用Docker运行Trivy</li><li>位置：终端</li><li>命令：<code>docker run --rm -v /var/run/docker.sock:/var/run/docker.sock aquasec/trivy image &lt;镜像名&gt;</code></li><li>成功标志：扫描结果正常显示</li><li>失败处理：检查Docker权限</li></ul><h3 id="备选路径2-下载二进制文件" tabindex="-1">备选路径2：下载二进制文件 <a class="header-anchor" href="#备选路径2-下载二进制文件" aria-label="Permalink to “备选路径2：下载二进制文件”">​</a></h3><p><strong>步骤1：下载二进制文件</strong></p><ul><li>目标：从GitHub Releases下载</li><li>位置：浏览器</li><li>操作：访问 <a href="https://github.com/aquasecurity/trivy/releases/latest/" target="_blank" rel="noreferrer">https://github.com/aquasecurity/trivy/releases/latest/</a> 下载对应平台的二进制文件</li><li>成功标志：文件下载完成</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><p><strong>步骤2：配置环境变量</strong></p><ul><li>目标：将Trivy添加到PATH</li><li>位置：终端</li><li>操作：将下载的二进制文件移动到PATH目录，或添加到PATH</li><li>成功标志：可以直接运行trivy命令</li><li>失败处理：检查文件权限</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><p><strong>扫描容器镜像</strong></p><ul><li>命令：<code>trivy image python:3.4-alpine</code></li><li>预期结果：显示镜像中的漏洞列表</li></ul><p><strong>扫描文件系统</strong></p><ul><li>命令：<code>trivy fs --scanners vuln,secret,misconfig ./</code></li><li>预期结果：显示文件系统中的安全问题</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>数据库下载失败</strong></p><ul><li>可能原因：网络问题</li><li>解决步骤：配置代理或使用离线数据库</li></ul></li><li><p><strong>Docker扫描权限错误</strong></p><ul><li>可能原因：Docker socket权限</li><li>解决步骤：使用sudo或添加用户到docker组</li></ul></li><li><p><strong>扫描结果为空</strong></p><ul><li>可能原因：目标不存在或路径错误</li><li>解决步骤：确认扫描目标正确</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://aquasecurity.github.io/trivy/" target="_blank" rel="noreferrer">Trivy Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li><a href="https://aquasecurity.github.io/trivy/latest/installation/" target="_blank" rel="noreferrer">Installation Guide</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',46)]))}const p=i(t,[["render",o]]);export{b as __pageData,p as default};
